import { Menu, MenuItem, Sidebar } from "react-pro-sidebar"
import {useNavigate ,Link} from "react-router-dom"

export const Home=()=>{
 const nav=useNavigate();
    return(
        <div>
            <h1 style={{ borderBottom:"2px solid #8a2be2 ",paddingInlineStart:10,marginTop:10,paddingBottom:10}}> Seja bem vindo !</h1>
        <Sidebar  style={{ display:"flex", marginInlineStart:8,marginTop:2,backgroundColor:"#8a2be2" }}
                image="'https://cdn-icons-png.flaticon.com/512/149/149071.png'"
        >   
            <Menu >
                <MenuItem 
                    onClick={() => { nav("/agendas") }}
                >
              Agendas
                </MenuItem>
                <MenuItem component={<Link to="/novoAgendamento" />}
                //onClick={()=>{nav("/novoAgendamento")}} 
                >                             
                 Criar agendamento
                </MenuItem>
            </Menu>
        </Sidebar>
        </div>
    )
}
